mapper.insert:

    SELECT PARTNER_SEQ.NEXTVAL FROM DUAL 


INSERT INTO partner (
    partner_id, member_id, partner_name, contact_name, 
    contact_phone, contact_email, partner_intro, status, created_at,
    business_number, has_exp, bank_name, account_number
) VALUES (
    #{partnerId}, #{memberId}, #{partnerName}, #{contactName}, 
    #{contactPhone}, #{contactEmail}, #{partnerIntro, jdbcType=CLOB}, 0, SYSDATE,
    #{businessNumber}, #{expStatus}, #{bankName}, #{accountNumber}
)

INSERT INTO partner_status (
    partner_status_id, partner_id, status_code, reg_date
) VALUES (
    SEQ_PARTNER_STATUS.NEXTVAL, #{partnerId}, 'PENDING', SYSDATE
)

INSERT INTO partner_file (
    file_id, partner_id, origin_file_name, file_url, file_type, created_at
) VALUES (
    PARTNER_FILE_SEQ.NEXTVAL, #{partnerId}, #{originFileName}, #{fileUrl}, #{fileType}, SYSDATE
)
